var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"제5 방위선 함락 후, 52시간 경과","JPN":"第5防衛線の陥落後、52時間経過","ENG":"52 hours after the fall of the 5th Defense Line","TWN":"第五防線淪陷後經過52小時"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"인류 통합 방위군 제4 방위선, 거점 기지","JPN":"人類統合防衛軍第4防衛線、拠点基地","ENG":"Base, United Humankind Defense Force's 4th Defense Line","TWN":"人類共同保衛軍第四防線基地"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"카운터 양성 계획?","JPN":"カウンター養成計画？","ENG":"Counter training project?","TWN":"制裁者培育計畫？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"그래, 따지고보면 소령은 내 선배쯤 된다고?","JPN":"ああ、つまり少佐はオレの先輩ってことになるな？","ENG":"Yeah. So technically, you, Major, are like my senior.","TWN":"嗯哼，算起來少校還是我的前輩吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그 프로젝트는, 분명 제 기수를 마지막으로 폐기되었을 텐데요?","JPN":"あのプロジェクトは、確か私の代を最後に廃止になったはずでは？","ENG":"I'm pretty sure that project got discontinued, with myself being one of the last candidates.","TWN":"那個計畫，明明最後已經廢止了吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"공식적으로는 그렇지.","JPN":"公式的にはな。","ENG":"Officially, yes.","TWN":"表面上是這樣。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"하지만 자네의 상관이었던 레지날드 준장은 음지에서 프로젝트를 이어나갔네.","JPN":"だが、君の上官であったレジナルド准将の手により、密かにプロジェクトは続けられた。","ENG":"But your superior, Brigadier General Dominic King Reginald, continued the project secretly.","TWN":"但你們的長官多明尼克準將暗地裡仍繼續進行這個計畫。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그는 원래부터 대의를 위해서라면 수단을 가리지 않는 성격이니 말이야.","JPN":"彼は元々、大義のためなら手段を選ばない性格だからな。","ENG":"He was always a stickler for doing anything for the greater good.","TWN":"他本來就是那種為達目的不擇手段的性格。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신, 우리 사령관님을 알고 있나요?","JPN":"あなた、私たちの司令官をご存じなんですか？","ENG":"You... You knew our commander?","TWN":"你……認識我們的司令官?"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그의 방식에 완전히 찬성하는 건 아니지만, 지금의 나라면 그를 이해할 수 있으니까.","JPN":"彼のやり方に完全に賛成するわけじゃないが、今の私なら彼を理解することができる。","ENG":"Although I don't completely agree with his methods, I can understand him now.","TWN":"我雖然不完全認可他的行事方式，但我現在可以理解他。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"흥! 이해고 나발이고 마음에 안 들어!","JPN":"ふん！　理解もなにも、オレは気に入らねえ！","ENG":"Hmph! Understanding or not, I don't like him!","TWN":"哼！什麼理解不理解的，我不喜歡他！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"그 인간은 나를 속이고, 실험용 쥐새끼처럼 대했단 말이야!","JPN":"あいつはオレを騙して、実験用のネズミみたいに扱ったんだ！","ENG":"He deceived me, and used me like some lab rat!","TWN":"那傢伙騙我，還把我當成實驗用的白老鼠！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"세계 멸망이니, 뭐니 헛소리나 잔뜩 떠들어대더니 먼저 뒈져버리고 말이야.","JPN":"世界の滅亡だの何だの、変なことばかり聞かせておいて、先に死んじまったしな。","ENG":"He always ranted nonsense about the world ending, and look where that got him. DEAD.","TWN":"什麼世界滅亡，滿嘴胡說八道，結果自己先死了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"하지만 결국 레지날드 준장이 없었다면 자네는 지금 이 자리에 없었을 걸세.","JPN":"しかし結局のところ、レジナルド准将がいなければ、君は今この場にいなかっただろう。","ENG":"But if it were not for Brigadier General Dominic King Reginald, you would not be here right now.","TWN":"但要不是多明尼克準將，你現在也不會在這裡。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"과정은 어떻다 해도, 결과적으로 레지날드 준장은 자네를 구한 셈이 되네만?","JPN":"過程はともあれ、結果的にレジナルド准将は君を助けたことになるな？","ENG":"No matter the process, strictly looking at the results, he did save you, did he not?","TWN":"先不談過程，從結果來看，多明尼克準將也算救了你一命？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"그건…… 그래서 뭐, 어쩌란 거야. 그 자식한테 고마워라도 하라고?","JPN":"それは……だからって何だよ。あいつに感謝でもしろってのか？","ENG":"That's... So what? What do you want me to do? Thank him?","TWN":"那是……所以呢？那又怎樣？我還得跟那傢伙說聲謝謝嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"묘지가 있다면 침이라도 뱉어주지.","JPN":"墓があったら、唾でも吐いてやる。","ENG":"I'll visit his grave just to spit on it.","TWN":"他要是有墓地，我一定會朝上面吐口水。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"안토노프, 당신 세계의 델타 세븐은 몇 번이나 세계를 구했다고 했죠?","JPN":"アントノフ、あなたの世界のデルタセブンは何度も世界を救ったと言いましたね？","ENG":"Antonov, you mentioned that your world's Delta Seven saved the world multiple times.","TWN":"安東諾夫，你們世界的第七三角洲部隊好幾次拯救了世界吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그렇게 축적한 기술과 장비로 다른 세계의 인류를 구하는 것이 당신의 사명이라고 했고요.","JPN":"蓄積した技術と装備で別の世界の人類を救うことが、あなたの使命だとも。","ENG":"And that it was your mission to save another world's human race with the technology and gear that you had accumulated.","TWN":"你說過你的使命就是帶著積累下來的技術和裝備，去拯救其他世界的人類。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그렇네.","JPN":"そうだ。","ENG":"Correct.","TWN":"沒錯。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그렇다면, 단도직입적으로 묻겠습니다.","JPN":"では、単刀直入にお聞きします。","ENG":"Then, I'll ask you a direct question.","TWN":"這樣的話……那我就不拐彎抹角了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신이 보유한 기술과 장비들로 이 세계의 4종 침식체, 아포리아를 공략할 수 있습니까?","JPN":"あなたが持っている技術と装備をもってすれば、この世界の第4種侵食体、アポリアを攻略できますか？","ENG":"With the technology and gear you have, can you defeat Aporia, a Category 4 C.O. from another world?","TWN":"你持有的這些技術和裝備，可以擊敗這個世界的4類侵蝕體阿波利亞嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"쓰러트릴 수 있네.","JPN":"倒せる。","ENG":"I can.","TWN":"可以。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"부탁드리겠습니다, 안토노프!! 부디, 저희 세계를 도와주세요!!","JPN":"お願いします、アントノフ！！　どうか、私たちの世界を助けてください！！","ENG":"Then I beg you, Antonov!! Please, help our world!!","TWN":"那我拜託你，安東諾夫！！拜託你一定要幫幫我們的世界！！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"소령?","JPN":"少佐？","ENG":"Major?","TWN":"少校？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카, 카린 양?","JPN":"か、カリンさん？","ENG":"K-Karin?","TWN":"卡，卡琳？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저희 세계에는 이제 더는 아포리아에게 대응할 수 있는 수단이 없습니다!!","JPN":"私たちの世界にはもう、アポリアに対抗できる手段が残っていません！！","ENG":"Our world has no way of defeating Aporia anymore!!","TWN":"我們世界已經沒有可以對付阿波利亞的辦法了！！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"반면, 아포리아는 상위종이 되기 위해 지금 이 순간에도 핵을 흡수하여 강해지고 있습니다!","JPN":"一方、アポリアは上位種になるために、今この瞬間にも核を吸収し、強くなっています！","ENG":"But even this second, Aporia is absorbing cores to become a high-category C.O.!","TWN":"另一方面，阿波利亞卻為了進化成高類侵蝕體，正在吸收核心變強！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"만약 그 괴물이 5종 침식체가 되어버린다면, 정말로 돌이킬 수 없는 사태가 발생합니다!","JPN":"もしあの化け物が第5種侵食体になれば、本当に取り返しがつかないことになってしまいます！","ENG":"If that monster becomes a Category 5 C.O., then the situation will be irreversible!","TWN":"萬一那個怪物進化成5類侵蝕體的話，就真的覆水難收了！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그 전에 부디…… 부디 한 번만 저희 세계를 도와주세요!","JPN":"そうなる前にどうか……一度だけ私たちの世界を助けてください！","ENG":"So please... Please help our world, just this once!","TWN":"在那之前，拜託……拜託你幫幫我們的世界！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그걸 위해서라면 저는 뭐든지 하겠습니다!","JPN":"そのためなら何だってします！","ENG":"I'll do anything you ask!","TWN":"為此，我願意做任何事！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신은 관리국에 대한 정보를 원하셨죠?","JPN":"あなたは管理局についての情報が欲しいんですよね？","ENG":"You wanted information on the Administration, correct?","TWN":"你想要管理局的情報吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"제가 알고 있는 모든 정보를 당신에게 제공해드리겠습니다!","JPN":"私の知っている情報をすべてあなたにお渡します！","ENG":"Then I'll provide you with everything I know!","TWN":"我可以把我知道的全都告訴你！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니까…… 그러니까 제발……!","JPN":"だから……だから、どうか……！","ENG":"So... So please...!","TWN":"所以……所以拜託了……！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"거절하지.","JPN":"断る。","ENG":"I refuse.","TWN":"我拒絕。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어째서! 어째서예요!","JPN":"どうして……どうしてですか！","ENG":"Why?! JUST WHY?!","TWN":"什麼！為什麼！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신이 정말로 델타 세븐의 일원이라면.","JPN":"あなたが本当にデルタセブンの一員なら。","ENG":"If you truly are a member of Delta Seven...","TWN":"你要真是第七三角洲部隊的一員。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"당신이 정말로 전우들의 시신 위에 서있는 이 기분을 조금이라도 이해한다면……!","JPN":"あなたが本当に戦友の死体を踏んで立っている気分を少しでも理解するなら……！","ENG":"If you understand what it feels like to stand on top of your fallen comrades...!","TWN":"如果你真的能理解站在戰友屍體上的那種心情………！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"멸망해가는 이 세계를 위해, 단 한 번의 호의를 베푸는 것이 그렇게 어려운 일인가요!?","JPN":"滅んでいくこの世界のために、たった一度だけ情けをかけてくれたっていいじゃありませんか！？","ENG":"Is it really that difficult to do a single favor for a dying world?","TWN":"為了這個瀕臨滅亡的的世界，釋出一次善意有那麼難嗎？！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"단 한 번의 호의? 남의 일이라고 너무 쉽게 말하는 군.","JPN":"一度だけの情けだと？　それはあまりにも身勝手な発言だな。","ENG":"A single favor? You make it sound like it is an easy task.","TWN":"一次善意？你把事情說的太簡單了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"정확히 18,342일이야.","JPN":"18,342日。","ENG":"It has been exactly 18,342 days.","TWN":"準確來說是18,342天。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"이 세계에 도달하는 데까지 걸린 시간이지.","JPN":"この世界にたどり着くまでかかった時間だ。","ENG":"That is how long it took for me to arrive on this world.","TWN":"我抵達這個世界所花的時間。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"뭐라고요?","JPN":"え？","ENG":"What?","TWN":"你說什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"고심도의 차원으로 다이브 해서 넘어 갈수록 시간의 흐름은 뒤틀리고 왜곡되지.","JPN":"高深度の次元にダイブすればするほど、時間の流れは歪み、捻じ曲がる。","ENG":"The more one dives into the hyperdepths, the more twisted and distorted the flow of time gets.","TWN":"躍入高深度次元後，時間的流逝會越來越扭曲和失真。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"내 기준에서 정확한 시간을 계산하기 위해선, 하루하루 잊지 않고 날짜를 세야 하거든.","JPN":"自分に流れる正確な時間を計算するには、毎日欠かさず日数を数えなければならない。","ENG":"For me to accurately calculate the amount of time that had passed, I had to count every single day.","TWN":"為了計算正確的時間，我日日夜夜數著日子。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"대략적으로는 <color=#ffd34c>50년</color>이라는 시간일세.","JPN":"だいたい、<color=#ffd34c>50年</color>かかっているんだ。","ENG":"That was approximately <color=#ffd34c>50 years</color> worth of time.","TWN":"大概花了<color=#ffd34c>50年</color>的時間。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그게 무슨?","JPN":"どういう意味ですか？","ENG":"What?","TWN":"你說什麼？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"잠깐! 무슨 소리야? 50년이라고?","JPN":"待ってくれ！　どういうことだ？　50年だって？","ENG":"Wait! You can't be serious! 50 years?!","TWN":"等一下！什麼意思？50年？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"안토노프 양은 지금 시간 여행이라도 한다는 뜻인가요?","JPN":"アントノフさんはタイムトラベラーが何かなんですか？","ENG":"Do you mean to say that you were time traveling, Antonov?","TWN":"意思是安東諾夫正在進行時間旅行嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"말했을 텐데, 론? 이건 시간 여행 같은 게 아니야.","JPN":"言ったはずだろう、ローン？　これはタイムトラベルなんかじゃない。","ENG":"Did I not tell you, Lone? This is not time traveling.","TWN":"我說過吧，隆利？這不是時間旅行。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"우리는 텔로미어 시술을 받아 노화를 극단적으로 늦출 수 있어.","JPN":"我々はテロメア施術を受けているため、老化を極限まで遅らせることができている。","ENG":"Our telomeres were altered to slow our aging to an extreme degree.","TWN":"我們可以透過端粒手術，盡可能地延緩衰老。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"애초에 노화를 늦출 수 있는 기술이 없었다면, 우리는 다른 세계로 넘어간다는 계획 자체를 세울 수가 없었어.","JPN":"そもそも老化を遅らせる技術がなかったら、我々は他の世界に飛ぶという計画そのものを立てていなかった。","ENG":"If we did not have this technology to slow our aging, this plan to traverse to another world would not have been possible in the first place.","TWN":"如果當初沒有這項的技術，我們前往其他世界的計畫也就無法實現。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"양자 위상이 크게 차이나는 세계로 단번에 다이브 했다간, 우리 몸의 구성 물질이 <color=#ffd34c>양자 분해</color>되어버리거든.","JPN":"量子位相が大きく異なる世界に一気にダイブしたら、我々の身体を構成する物質が<color=#ffd34c>量子分解</color>されてしまうからな。","ENG":"Our bodies become <color=#ffd34c>quantum decomposed</color> when diving into a world where the quantum phase is so vastly different.","TWN":"當躍入一個量子位相差異過大的世界，我們身體的組成物質就會被<color=#ffd34c>量子分解</color>。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"양자 분해라고? 설마?","JPN":"量子分解？　まさか？","ENG":"Quantum decomposed? What?","TWN":"量子分解？難道是？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"슈뢰딩거의 고양이를 떠올리면 된다네.","JPN":"シュレーディンガーの猫をイメージするといいだろう。","ENG":"Think about Schrödinger's cat.","TWN":"想一想薛丁格的貓吧。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"운이 좋으면, 원래 세계로 복귀하는 것으로 끝날 수도 있지만.","JPN":"運が良ければ、元の世界に復帰して終わる可能性もあるが。","ENG":"If we are lucky, it will just return us to our original world, but...","TWN":"運氣好的話，還可以返回原本的世界。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"반대라면, 몸의 구성 원소가 철저하게 파괴되어 완전히 소멸하게 되지.","JPN":"その反対だと、身体の構成要素が徹底的に破壊され、完全に消滅してしまう。","ENG":"If not, our bodies will dematerialize into nothing.","TWN":"反之，身體的組成元素會徹底被破壞，就此消失。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"따라서 양자 분해를 극복하는 방법으로 우리는 <color=#ffd34c>시간</color>을 택했네.","JPN":"そこで我々は、量子分解を克服するために、<color=#ffd34c>時間</color>を選んだ。","ENG":"So, we chose to slow <color=#ffd34c>time</color> in order to counteract the quantum decomposition.","TWN":"因此，我們選擇了<color=#ffd34c>時間</color>作為克服量子分解的辦法。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"잠수부가 한 번에 깊은 곳까지 잠수하지 않는 것처럼.","JPN":"潜水士が一気に深いところまで潜らないとの同じように。","ENG":"Just like how a scuba diver slowly dives down into the depths of the oceans...","TWN":"就像潛水員不會一下子就潛到水底深處一樣。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"천천히, 조금씩, 양자 위상의 차이를 몸에 적응시켜가면서 다이브 하는 거지.","JPN":"ゆっくり、少しずつ、量子位相の相違を身体に慣れさせつつ、ダイブしていくんだ。","ENG":"We allowed our bodies to gradually adjust to the quantum phase difference.","TWN":"慢慢地，一點點地躍入，讓身體逐漸適應這個差異。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그렇게 차원을 유랑한 시간이 50년이야.","JPN":"そうやって次元を彷徨いながら50年を過ごした。","ENG":"And that is how I wandered dimensions for 50 years.","TWN":"就這樣，在次元流浪了50年。"},"stage":{"bg":"COUNTERSIDE_GREEN","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"노화를 극단적으로 늦추긴 했지만, 우리에게도 50년이라는 시간은 결코 적지 않아.","JPN":"老化を極限まで遅らせはしたが、我々にも50年という時間は決して短いわけじゃない。","ENG":"Although I slowed down my aging to the extreme, 50 years is still a long time for us.","TWN":"雖然盡可能地延緩了衰老，但對於我們來說，50年的時間不算短。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"한 번 항해를 실패한 시점에서 나는 이미 많은 걸 소모해버렸네.","JPN":"一度航海に失敗した時点で、私はすでに多くを消耗している。","ENG":"I wasted too much time already with one failed voyage.","TWN":"一次失敗的航行，已經讓我損失很多。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"우리가 보유한 물적 자원도 인적 자원도, 그리고 나 스스로도 한계에 다다랐지.","JPN":"我々が有する物的資源も、人的資源も、そして私自身も限界に達した。","ENG":"The ship's supplies, the manpower, and even myself. They have all reached their limits.","TWN":"我們持有的物質資源也好，人力資源也好，就連我自己也達到了極限。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"아마도 다음 항해가 내 마지막이 될 거야.","JPN":"おそらく次の航海が私の最後の航海になるだろう。","ENG":"I believe my next departure will be my last.","TWN":"也許下一次就是我最後的航行了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어째서…….","JPN":"どうして……","ENG":"But why...?","TWN":"為什麼……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"어째서냐고?","JPN":"どうしてだと？","ENG":"Why, you ask?","TWN":"為什麼嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그러는 자네는 어째서 이 세계를 포기하지 않는 거지?","JPN":"ならば、君はどうしてこの世界を諦めないんだ？","ENG":"Then why have you not given up on this world already?","TWN":"那你們呢，為什麼不放棄這個世界？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"이 세계는, 자네와 함께한 전우들을 희생시켜가면서까지 지켜야만 하는 세계인가?","JPN":"この世界は、君と共に戦った戦友たちを犠牲にしてまで守らなければいけない世界なのか？","ENG":"This world–is it worth protecting it even at the cost of sacrificing your comrades?","TWN":"這個世界是一個必須犧牲你和你的戰友來保護的世界嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그, 그건…….","JPN":"そ、それは……","ENG":"Th-that's...","TWN":"那，那個……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L8_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"자네는 도망치는 게 꼴사납다고 했지?","JPN":"君は逃げることが惨めだと言ったな？","ENG":"You said it was cowardly to run away.","TWN":"你覺得逃跑很丟臉吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"하지만 살 수 있는 선택지가 있는데, 일부러 그걸 선택하지 않는 건 단순한 아집일 뿐이지 않은가.","JPN":"しかし助かるかもしれないという選択肢があるのに、あえてそれを選ばないのはただのエゴじゃないのか。","ENG":"But it is your stubbornness that prevents you from choosing to live when the opportunity presents itself.","TWN":"但是明明有能活下去的可能，卻故意忽略，這只是單純的固執。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"비록, 멸망을 앞두고 있지만……","JPN":"たとえ、滅ぶ運命だとしても……","ENG":"Even though we are on the brink of destruction...","TWN":"雖然，瀕臨滅亡……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L12_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저에게 이 세계는 앞서 간 대원들이 목숨을 바쳐 지켜준 소중한 세계입니다.","JPN":"私にとってこの世界は先立った仲間たちが守ってくれた大切な世界です。","ENG":"Our fallen comrades gave their lives to protect their precious home.","TWN":"但對我來說，這個世界，是那些犧牲的隊員們付出生命才守住的寶貴世界。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그러니까, 저는 이 세계를 포기할 수 없어요.","JPN":"だから、私はこの世界を諦められません。","ENG":"That's why I can't abandon this world.","TWN":"所以我無法放棄。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"거지 같아서 못 들어주겠네, 진짜!","JPN":"あーくっせぇ、聞いてられねえよ！","ENG":"This is so stupid, I can't listen to her anymore!","TWN":"我聽不下去了！你到底在說什麼鬼話！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"뭐라고요? 당신 지금!","JPN":"何ですって？　あなた今何と！","ENG":"What? What did you just say?!","TWN":"你說什麼！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"기껏 구해줬더니, 이런 얼빠진 소리나 지껄일 줄이야!","JPN":"せっかく助けたのに、そんなくだらないことばかりぬかしやがって！","ENG":"We saved your butt and all you do is spit out nonsense!","TWN":"我們好不容易救了你，你卻說這種傻話？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"소중한 세계? 그래! 댁들 같이 높으신 분들에게는 이 세계가 퍽이나 소중하겠지!","JPN":"大切な世界？　そうだな！　お前らみたいなお偉いさんにとっては、よっぽど大切だろうよ！","ENG":"Your precious home? Sure! I'm sure it's soooo precious to higher-ups like you!","TWN":"寶貴的世界？哼！對於像你這種高高在上的人來說，這個世界一定很寶貴吧！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"하지만 나는 말이야! 이 망할 세계에 태어나서 지금까지 단 한 번도 행복했던 적이 없어!","JPN":"でもオレはな！　このくそったれの世界に生まれて一度も幸せだったことがないんだ！","ENG":"But for me! I was never once happy to be born in this stupid world!","TWN":"但對我來說！從這該死的世界出生到現在，從來沒有幸福過一天！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"지옥이나 다름없는, 거지 같은 세계였다고! 제기랄!","JPN":"地獄みたいな、クソみたいな世界だったんだ、ちくしょう！","ENG":"It's nothing more than a cruel, stupid world! Ugh!","TWN":"這就是個如同地獄般生不如死的世界！該死！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"레베카!!","JPN":"レベッカ！！","ENG":"Rebecca!","TWN":"蕾貝卡！！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"알았어! 알았다고! 빠지면 되잖아!","JPN":"わかった、わかったって。引っ込んでいればいいんだろ！","ENG":"I know! Fine! I'll stay out of it!","TWN":"知道了！知道了！不說就不說！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"나도 싫어! 저런 헛소리를 더 듣고 있다간, 내 위장이 먼저 뒤틀려 버릴 것 같으니까!","JPN":"こっちこそ願い下げだ！　あんな戯言をこれ以上聞くのはオレが耐えられない！","ENG":"I hate this too! I think my stomach's gonna get tied in a knot if I hear any more of this!","TWN":"我也不想的！但如果讓我再聽到那種鬼話，我就要吐了！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"실례했군. 무례를 사과하지.","JPN":"失礼した。無礼を詫びよう。","ENG":"Excuse us. I apologize on her behalf.","TWN":"失禮了。我為她的無禮向你道歉。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"하지만 한때 관리국에 다다랐던 자네들이 <color=#ffd34c>길잡이</color>가 되어준다면, 우리로서는 꽤나 리스크를 줄일 수 있는 것도 사실이야.","JPN":"だが一度管理局に辿りついたことのある君たちが<color=#ffd34c>案内役</color>になってくれるなら、リスクを大きく減らせることも事実だ。","ENG":"But since you have reached the Administration before, it is true that you would be of help in lowering our risks if you became our <color=#ffd34c>Pathfinder</color>.","TWN":"如果有去過管理局的你們作為<color=#ffd34c>引路人</color>的話，我們的風險確實會小很多。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"자네들이 협력하지 않으면, 우리는 우리 스스로 대책을 강구할 수밖에 없어.","JPN":"君たちが協力してくれなければ、我々は自分たちで対策を講じなければならないからな。","ENG":"However, if you do not wish to cooperate, we have no choice but to find a solution on our own.","TWN":"但若你們不願提供協助的話，我們也只能自己想辦法了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"설령, 그것이 자네들과 대립하게 될 지라도 말이야.","JPN":"たとえ、それによって君たちと対立することになってもだ。","ENG":"Even if that means going up against you all.","TWN":"即使，會與你們對立。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그러니 자네들에게 마지막으로 제안하지.","JPN":"だから、最後にもう一度だけ君たちに提案をしよう。","ENG":"Here is my last proposition for you all.","TWN":"所以，我最後向你們提出邀請。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"멸망해 가는 이 세계를 뒤로하고 우리와 함께 관리국이 존재하는 세계로 나가지 않겠나?","JPN":"滅んでいくこの世界を後にし、我々と共に管理局の存在する世界を目指さないか？","ENG":"Will you leave this dying world and join us to the world where the Administration exists?","TWN":"要不要拋下這個瀕臨滅亡的世界，與我們一同前往管理局所在的世界？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};